        "id": "monster-astral-dreadnought",
        "slug": "astral-dreadnought",
        "name": "Astral Dreadnought",
        "sourceUrl": "https://www.aidedd.org/dnd/monstres.php?vo=astral-dreadnought",
        "challengeRating": "21",
        "creatureType": "Monstrosity (titan)",
        "creatureCategory": "Monstrosity",
        "size": "Gargantuan",
        "armorClass": 20,
        "hitPoints": 297,
        "speed": "15 ft., fly 80 ft. (hover)",
        "alignment": "unaligned",
        "legendary": true,
        "sourceLabel": "Mordenkainen's Tome of Foes",
        "savingThrows": "Dex +5, Wis +9",
        "skills": "Perception +9",
        "damageVulnerabilities": "",
        "damageResistances": "bludgeoning, piercing, and slashing from nonmagical attacks",
        "damageImmunities": "",
        "conditionImmunities": "charmed, exhaustion, frightened, paralyzed, petrified, poisoned, prone, stunned",
        "senses": "darkvision 120 ft., passive Perception 19",
        "languages": "—",
        "challengeXp": "33000 XP",
        "traits": [
            {
                "title": "Antimagic Cone",
                "text": "The dreadnought's eye creates an area of antimagic, as in the antimagic field spell, in a 150-foot cone. At the start of each of its turns, it decides which way the cone faces. The cone doesn't function while the eye is closed or while the dreadnought is blinded."
            },
            {
                "title": "Astral Entity",
                "text": "he dreadnought can't leave the Astral Plane, nor can it be banished or otherwise transported out of that plane."
            },
            {
                "title": "Demiplanar Donjon",
                "text": "Anything the dreadnought swallows is transported to a demiplane that can be entered by no other means except a wish spell or the dreadnought's Bite and Donjon Visit. A creature can leave the demiplane only by using magic that enables planar travel, such as the plane shift spell. The demiplane resembles a stone cave roughly 1,000 feet in diameter with a ceiling 100 feet high. Like a stomach, it contains the remains of past meals. The dreadnought can't be harmed from within the demiplane. If the dreadnought dies, the demiplane disappears, and everything inside it appears around the dreadnought's corpse. The demiplane is otherwise indestructible."
            },
            {
                "title": "Legendary Resistance (3/Day)",
                "text": "If the dreadnought fails a saving throw, it can choose to succeed instead."
            },
            {
                "title": "Sever Silver Cord",
                "text": "If the dreadnought scores a critical hit against a creature traveling by means of the astral projection spell, the dreadnought can cut the target's silver cord instead of dealing damage."
            },
            {
                "title": "Unusual Nature",
                "text": "The dreadnought doesn't require air, food, drink, or sleep."
            }
        ],
        "actions": [
            {
                "title": "Multiattack",
                "text": "The dreadnought makes one Bite attack and two Claw attacks."
            },
            {
                "title": "Bite",
                "text": "Melee Weapon Attack : +16 to hit, reach 10 ft., one target. Hit : 36 (5d10 + 9) force damage. If the target is a Huge or smaller creature and this damage reduces it to 0 hit points or it is incapacitated, the dreadnought swallows it. The swallowed target, along with everything it is wearing and carrying, appears in an unoccupied space on the floor of the Demiplanar Donjon."
            },
            {
                "title": "Claw",
                "text": "Melee Weapon Attack : +16 to hit, reach 20 ft., one target. Hit : 19 (3d6 + 9) force damage."
            }
        ],
        "reactions": [],
        "legendaryActions": [
            {
                "title": "",
                "text": "The dreadnought can take 3 legendary actions, choosing from the options below. Only one legendary option can be used at a time and only at the end of another creature's turn. The dreadnought regains spent legendary actions at the start of its turn."
            },
            {
                "title": "Claw",
                "text": "The dreadnought makes one Claw attack."
            },
            {
                "title": "Donjon Visit (Costs 2 Actions)",
                "text": "One Huge or smaller creature that the dreadnought can see within 60 feet of it must succeed on a DC 19 Charisma saving throw or be teleported to an unoccupied space on the floor of the Demiplanar Donjon. At the end of the target's next turn, it reappears in the space it left or in the nearest unoccupied space if that space is occupied."
            },
            {
                "title": "Psychic Projection (Costs 3 Actions)",
                "text": "Each creature within 60 feet of the dreadnought must make a DC 19 Wisdom saving throw, taking 26 (4d10 + 4) psychic damage on a failed save, or half as much damage on a successful one."
            }
        ],
