        "challengeXp": "25000 XP",
        "traits": [
            {
                "title": "Death Throes",
                "text": "When Belaphoss dies, he explodes, and each creature within 30 feet of him must make a DC 20 Dexterity saving throw, taking 70 (20d6) fire damage on a failed save, or half as much damage on a successful one. The explosion ignites flammable objects in that area that aren't being worn or carried, and it destroys Belaphoss's weapon."
            },
            {
                "title": "Fire Aura",
                "text": "At the start of each of Belaphoss's turns, each creature within 5 feet of him takes 10 (3d6) fire damage, and flammable objects in the aura that aren't being worn or carried ignite. A creature that touches Belaphoss or hits him with a melee attack while within 5 feet of him takes 10 (3d6) fire damage."
            },
            {
                "title": "Magic Resistance",
                "text": "Belaphoss has advantage on saving throws against spells and other magical effects."
            },
            {
                "title": "Magic Weapons",
                "text": "Belaphoss's weapon attacks are magical."
            }
        ],
        "actions": [
            {
                "title": "Multiattack",
                "text": "Belaphoss makes two attacks: one with his greataxe and one with his whip."
            },
            {
                "title": "Greataxe",
                "text": "Melee Weapon Attack : +14 to hit, reach 10 ft., one target. Hit : 24 (3d10 + 8) slashing damage plus 13 (3d8) fire damage. If Belaphoss scores a critical hit, he rolls damage dice three times, instead of twice."
            },
            {
                "title": "Whip",
                "text": "Melee Weapon Attack : +14 to hit, reach 30 ft., one target. Hit : 15 (2d6 + 8) slashing damage plus 10 (3d6) fire damage, and the target must succeed on a DC 20 Strength saving throw or be pulled up to 25 feet toward Belaphoss."
            },
            {
                "title": "Abyssal Storm (Recharge 5–6)",
                "text": "Belaphoss surrounds himself with explosive fire that fills a 30-foot sphere centered on him and spreads around corners. Each creature in the fire must make a Dexterity saving throw, taking 28 (8d6) fire damage and 28 (8d6) bludgeoning damage on a failed save, or half as much damage on a successful one. Belaphoss is immune to this damage. Objects in the area are subject to it, and the fire ignites flammable objects in the area that aren't being worn or carried."
            },
            {
                "title": "Teleport",
                "text": "Belaphoss magically teleports, along with any equipment he is wearing or carrying, up to 120 feet to an unoccupied space he can see."
            },
            {
                "title": "Winged Barrage",
                "text": "Belaphoss beats his wings. Each creature in a 20-foot cube originating from him must make a DC 20 Dexterity saving throw. On a failure, a target takes 29 (6d6 + 8) bludgeoning damage and is pushed 20 feet away from Belaphoss. On a success, the target takes half the bludgeoning damage and isn't pushed. Belaphoss can then fly up to half his flying speed."
            }
        ],
