        "actions": [
            {
                "title": "Dagger",
                "text": "Melee or Ranged Weapon Attack : +4 to hit, reach 5 ft. or range 20/60 ft., one target. Hit : 4 (1d4 + 2) piercing damage."
            },
            {
                "title": "Sling",
                "text": "Ranged Weapon Attack : +4 to hit, range 30/120 ft., one target. Hit : 4 (1d4 + 2) bludgeoning damage."
            },
            {
                "title": "Weapon Invention",
                "text": "The kobold uses one of the following options (choose one or roll a d8); the kobold can use each one no more than once per day:"
            },
            {
                "title": "1- Acid",
                "text": "The kobold hurls a flask of acid. Ranged Weapon Attack : +4 to hit, range 5/20 ft., one target. Hit : 7 (2d6) acid damage."
            },
            {
                "title": "2- Alchemist's Fire",
                "text": "The kobold throws a flask of alchemist's fire. Ranged Weapon Attack : +4 to hit, range 5/20 ft., one target. Hit : 2 (1d4) fire damage at the start of each of the target's turns. The target can end this damage by using its action to make a DC 10 Dexterity check to extinguish the flames."
            },
            {
                "title": "3- Basket of Centipedes",
                "text": "The kobold throws a small basket into a 5-foot-square space within 20 feet of it. A swarm of insects (centipedes) with 11 hit points emerges from the basket and rolls initiative. At the end of each of the swarm's turns, there's a 50 percent chance that the swarm disperses."
            },
            {
                "title": "4- Green Slime Pot",
                "text": "The kobold throws a clay pot full of green slime at the target, and it breaks open on impact. Ranged Weapon Attack : +4 to hit, range 5/20 ft., one target. Hit : 5 (1d10) acid damage, and the target is covered in slime until a creature uses its action to scrape or wash the slime off. A target covered in the slime takes 5 (1d10) acid damage at the start of each of its turns."
            },
            {
                "title": "5- Rot Grub Pot",
                "text": "The kobold throws a clay pot into a 5-foot-square space within 20 feet of it, and it breaks open on impact. A swarm of rot grubs (in this book) emerges from the shattered pot and remains a hazard in that square."
            },
            {
                "title": "6- Scorpion on a Stick",
                "text": "The kobold makes a melee attack with a scorpion tied to the end of a 5-foot-long pole. Melee Weapon Attack : +4 to hit, reach 5 ft., one target. Hit : 1 piercing damage, and the target must make a DC 9 Constitution saving throw, taking 4 (1d8) poison damage on a failed save, or half as much damage on a successful one."
            },
            {
                "title": "7- Skunk in a Cage",
                "text": "The kobold releases a skunk into an unoccupied space within 5 feet of it. The skunk has a walking speed of 20 feet, AC 10, 1 hit point, and no effective attacks. It rolls initiative and, on its turn, uses its action to spray musk at a random creature within 5 feet of it. The target must succeed on a DC 9 Constitution saving throw, or it retches and is incapacitated for 1 minute. The target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. A creature that doesn't need to breathe or is immune to poison automatically succeeds on the saving throw. Once the skunk has sprayed its musk, it can't do so again until it finishes a short or long rest."
            },
            {
                "title": "8- Wasp Nest in a Bag",
                "text": "The kobold throws a small bag into a 5-foot-square space within 20 feet of it. A swarm of insects (wasps) with 11 hit points emerges from the bag and rolls initiative. At the end of each of the swarm's turns, there's a 50 percent chance that the swarm disperses."
            }
        ],
