        "traits": [
            {
                "title": "Regeneration",
                "text": "The revenant regains 10 hit points at the start of its turn. If the revenant takes fire or radiant damage, this trait doesn't function at the start of the revenant's next turn. The revenant's body is destroyed only if it starts its turn with 0 hit points and doesn't regenerate."
            },
            {
                "title": "Rejuvenation",
                "text": "When the revenant's body is destroyed, its soul lingers. After 24 hours, the soul inhabits and animates another humanoid corpse on the same plane of existence and regains all its hit points. While the soul is bodiless, a wish spell can be used to force the soul to go to the afterlife and not return."
            },
            {
                "title": "Turn Immunity",
                "text": "The revenant is immune to effects that turn undead."
            },
            {
                "title": "Vengeful Tracker",
                "text": "The revenant knows the distance to and direction of any creature against which it seeks revenge, even if the creature and the revenant are on different planes of existence. If the creature being tracked by the revenant dies, the revenant knows."
            }
        ],
        "actions": [
            {
                "title": "Multiattack",
                "text": "The revenant makes two fist attacks."
            },
            {
                "title": "Fist",
                "text": "Melee Weapon Attack : +7 to hit, reach 5 ft., one target. Hit : 11 (2d6 + 4) bludgeoning damage. If the target is a creature against which the revenant has sworn vengeance, the target takes an extra 14 (4d6) bludgeoning damage. Instead of dealing damage, the revenant can grapple the target (escape DC 14) provided the target is Large or smaller."
            },
            {
                "title": "Vengeful Glare",
                "text": "The revenant targets one creature it can see within 30 feet of it and against which it has sworn vengeance. The target must make a DC 15 Wisdom saving throw. On a failure, the target is paralyzed until the revenant deals damage to it, or until the end of the revenant's next turn. When the paralysis ends, the target is frightened of the revenant for 1 minute. The frightened target can repeat the saving throw at the end of each of its turns, with disadvantage if it can see the revenant, ending the frightened condition on itself on a success."
            }
        ],
